rows = []
sort = 1
for provider, uids in games.items():
    for uid in uids:
        rows.append({
            "name": uid[:12].upper(),
            "provider": provider,
            "thumbnail_url": f"{CDN}/{provider}/{uid}.jpg",
            "player_count": (sort % 500) + 50,
            "is_new": sort % 7 == 0,
            "is_hot": sort % 13 == 0,
            "category": "slots",
            "sort_order": sort
        })
        sort += 1

print(f"Total games: {len(rows)}")

# Insert in batches of 50
batch_size = 50
total_inserted = 0

for i in range(0, len(rows), batch_size):
    batch = rows[i:i+batch_size]
    payload = json.dumps(batch).encode()
    req = urllib.request.Request(
        f"{SUPA_URL}/rest/v1/games",
        data=payload,
        method="POST",
        headers={
            "Authorization": f"Bearer {KEY}",
            "apikey": KEY,
            "Content-Type": "application/json",
            "Prefer": "return=minimal"
        }
    )
    try:
        res = urllib.request.urlopen(req)
        total_inserted += len(batch)
        print(f"✅ Batch {i//batch_size + 1}: {total_inserted}/{len(rows)}")
    except urllib.error.HTTPError as e:
        print(f"❌ Batch {i//batch_size + 1}: {e.read().decode()[:100]}")
    time.sleep(0.2)

print(f"Done! Total: {total_inserted} games inserted")
